const TextField = ({label, title, value, callback} : any) => {

    return (
        <label className="col-form-label">
            {label}<input className="form-control" title={title} type="text" name={title} onChange={(e) => {callback = e.target.value}}></input>        
        </label>
    )
}

export default TextField;
